// Validate and process incoming ad space order
const body = $input.first().json.body;

// Required fields
const required = ['business_name', 'contact_name', 'contact_email', 'mailer_id'];
const missing = required.filter(f => !body[f]);

if (missing.length > 0) {
  return [{
    json: {
      success: false,
      error: `Missing required fields: ${missing.join(', ')}`,
      status: 400
    }
  }];
}

// Find next available slot for this mailer
return [{
  json: {
    success: true,
    business_name: body.business_name,
    contact_name: body.contact_name,
    contact_email: body.contact_email,
    contact_phone: body.phone || '',
    mailer_id: body.mailer_id,
    placement: body.placement || 'standard',
    ad_headline: body.ad_headline || '',
    ad_description: body.ad_description || '',
    price: body.price || 550.00
  }
}];

const slot = $input.first().json;
const order = $('Validate Order').first().json;

if (!slot || !slot.id) {
  return [{
    json: {
      success: false,
      error: 'No available slots for this mailer. All spaces are filled!',
      status: 409
    }
  }];
}

return [{
  json: {
    ...order,
    slot_id: slot.id,
    slot_number: slot.slot_number,
    reserved_until: new Date(Date.now() + 48 * 60 * 60 * 1000).toISOString()
  }
}];

// Create Stripe checkout session URL
// In production, use Stripe API to create a checkout session
const slot = $input.first().json;

// For now, return a placeholder — replace with actual Stripe integration
const stripeLink = `https://buy.stripe.com/YOUR_STRIPE_LINK?client_reference_id=${slot.slot_id}`;

return [{
  json: {
    success: true,
    slot_number: slot.slot_number,
    business_name: slot.business_name,
    price: slot.price,
    reserved_until: slot.reserved_until,
    payment_url: stripeLink,
    message: `Slot ${slot.slot_number} reserved for ${slot.business_name}. Payment due within 48 hours.`
  }
}];
